#include<bits/stdc++.h>
using namespace std;
const long long N=1e6+10;
long long l,r,f[N],buc[N];
bool vis[N];
long long gcd(long long a,long long b)
{
    return(b==0?a:gcd(b,a%b));
}
long long lcm(long long a,long long b)
{
    return a/gcd(a,b)*b;
}
long long find(long long x)
{
    return(f[x]==x?x:f[x]=find(f[x]));
}
struct node
{
    long long l,r;
    long long w;
    bool operator<(const node&b)const
    {
        return w<b.w;
    }
};
vector<node> e;

int main()
{
    scanf("%lld%lld",&l,&r);
    long long ans=0;
    for(long long i=l;i<=r;i++)
    {
        f[i]=i;
        buc[i]=1;
    }
    for(long long i=2;i<=r;i++)
    {
        long long first=0;
        for(long long j=i;j<=r;j+=i)
        {
            if(buc[j]&&!first)
            {
                first=j;
            }
            if(buc[j])
            {
                e.push_back((node){first,j,lcm(first,j)});
            }
            vis[j]=1;
        }
        if(i>=l)
        {
            e.push_back((node){first,l,lcm(first,l)});
        }
    }
    sort(e.begin(),e.end());
    for(auto i:e)
    {
        long long u=i.l,v=i.r;
        long long w=i.w;
        if(find(u)!=find(v))
        {
            f[max(find(u),find(v))]=min(find(u),find(v));
            ans+=w;
        }
    }
    printf("%lld",ans);
    return 0;
}
